     1→/**
     2→ * GestureController - MediaPipe HandLandmarker integration with
     3→ * ONNX-based MLP gesture classification.
     4→ *
     5→ * Gestures detected (via trained MLP model):
     6→ *   "pinch"     - Thumb tip close to index tip
     7→ *   "fist"      - All fingers curled
     8→ *   "open_hand" - All fingers extended
     9→ *   "frame"     - Two hands forming a rectangle (bypass: both hands detected)
    10→ *   "none"      - No hand or ambiguous pose
    11→ */
    12→class GestureController {
    13→  // Label order matches sklearn LabelEncoder.fit() alphabetical sorting
    14→  static GESTURE_LABELS = ['fist', 'frame', 'none', 'open_hand', 'pinch'];
    15→
    16→  /**
    17→   * @param {HTMLVideoElement} videoElement
    18→   * @param {function} onGestureChange - Called when gesture changes: (gesture, confidence, handPos)
    19→   */
    20→  constructor(videoElement, onGestureChange) {
    21→    this.video = videoElement;
    22→    this.onGestureChange = onGestureChange;
    23→
    24→    this.handLandmarker = null;
    25→    this.camera = null;
    26→    this.running = false;
    27→
    28→    // ONNX inference session
    29→    this.session = null;
    30→    this._isInferring = false;
    31→    this._lastPrediction = { gesture: 'none', confidence: 0 };
    32→
    33→    // Current state
    34→    this._gesture = 'none';
    35→    this._confidence = 0;
    36→    this._handPosition = null; // { x, y } normalized 0-1
    37→    this._landmarks = null;
    38→
    39→    // Debounce: require N consecutive frames of same gesture
    40→    this._gestureBuffer = [];
    41→    this._bufferSize = 3;
    42→
    43→    // Confidence threshold
    44→    this._confidenceThreshold = 0.7;
    45→
    46→    // Canvas for skeleton overlay
    47→    this.overlayCanvas = null;
    48→    this.overlayCtx = null;
    49→
    50→    // Animation frame
    51→    this._animFrameId = null;
    52→  }
    53→
    54→  /**
    55→   * Initialize detector only (MediaPipe + ONNX) without starting camera or loop.
    56→   * Use this when you manage the camera and render loop externally.
    57→   * After calling this, use detectRaw(video) per frame.
    58→   * @returns {Promise<void>}
    59→   */
    60→  async initDetector() {
    61→    const vision = await this._loadMediaPipe();
    62→    const { HandLandmarker, FilesetResolver } = vision;
    63→
    64→    const wasmFileset = await FilesetResolver.forVisionTasks(
    65→      'https://cdn.jsdelivr.net/npm/@mediapipe/tasks-vision@latest/wasm'
    66→    );
    67→
    68→    this.handLandmarker = await HandLandmarker.createFromOptions(wasmFileset, {
    69→      baseOptions: {
    70→        modelAssetPath:
    71→          'https://storage.googleapis.com/mediapipe-models/hand_landmarker/hand_landmarker/float16/latest/hand_landmarker.task',
    72→        delegate: 'GPU',
    73→      },
    74→      runningMode: 'VIDEO',
    75→      numHands: 2,
    76→      minHandDetectionConfidence: 0.5,
    77→      minHandPresenceConfidence: 0.5,
    78→      minTrackingConfidence: 0.5,
    79→    });
    80→
    81→    await this._initONNXSession();
    82→  }
    83→
    84→  /**
    85→   * Detect hands in a video frame. Returns raw MediaPipe results.
    86→   * Call this per-frame from your own render loop.
    87→   * @param {HTMLVideoElement} video
    88→   * @returns {object|null} MediaPipe detection results with .landmarks array
    89→   */
    90→  detectRaw(video) {
    91→    if (!this.handLandmarker || video.readyState < 2) return null;
    92→    return this.handLandmarker.detectForVideo(video, performance.now());
    93→  }
    94→
    95→  /**
    96→   * Classify a single hand's landmarks using ONNX (or heuristic fallback).
    97→   * @param {Array} landmarks - 21 MediaPipe hand landmarks
    98→   * @returns {Promise<{gesture: string, confidence: number}>}
    99→   */
   100→  async classifyLandmarksAsync(landmarks) {
   101→    if (this.session && !this._isInferring) {
   102→      this._isInferring = true;
   103→      try {
   104→        await this._runInference(landmarks);
   105→      } finally {
   106→        this._isInferring = false;
   107→      }
   108→      return { ...this._lastPrediction };
   109→    }
   110→    // Fallback to heuristic
   111→    return this._classifyGesture(landmarks);
   112→  }
   113→
   114→  /**
   115→   * Initialize MediaPipe, ONNX session, and start processing.
   116→   * @returns {Promise<void>}
   117→   */
   118→  async init() {
   119→    // Import MediaPipe vision module from CDN
   120→    const vision = await this._loadMediaPipe();
   121→
   122→    const { HandLandmarker, FilesetResolver } = vision;
   123→
   124→    const wasmFileset = await FilesetResolver.forVisionTasks(
   125→      'https://cdn.jsdelivr.net/npm/@mediapipe/tasks-vision@latest/wasm'
   126→    );
   127→
   128→    this.handLandmarker = await HandLandmarker.createFromOptions(wasmFileset, {
   129→      baseOptions: {
   130→        modelAssetPath:
   131→          'https://storage.googleapis.com/mediapipe-models/hand_landmarker/hand_landmarker/float16/latest/hand_landmarker.task',
   132→        delegate: 'GPU',
   133→      },
   134→      runningMode: 'VIDEO',
   135→      numHands: 2,
   136→      minHandDetectionConfidence: 0.5,
   137→      minHandPresenceConfidence: 0.5,
   138→      minTrackingConfidence: 0.5,
   139→    });
   140→
   141→    // Initialize ONNX inference session
   142→    await this._initONNXSession();
   143→
   144→    // Start camera
   145→    await this._startCamera();
   146→    this.running = true;
   147→    this._processLoop();
   148→  }
   149→
   150→  /** Initialize ONNX Runtime inference session. */
   151→  async _initONNXSession() {
   152→    try {
   153→      this.session = await ort.InferenceSession.create('./mlp_model.onnx', {
   154→        executionProviders: ['wasm'],
   155→      });
   156→      console.log('ONNX session initialized.');
   157→    } catch (e) {
   158→      console.warn('ONNX session failed to load, falling back to heuristic:', e);
   159→      this.session = null;
   160→    }
   161→  }
   162→
   163→  /** Dynamically import the MediaPipe vision module. */
   164→  async _loadMediaPipe() {
   165→    // Use dynamic import from CDN
   166→    const module = await import(
   167→      'https://cdn.jsdelivr.net/npm/@mediapipe/tasks-vision@latest'
   168→    );
   169→    return module;
   170→  }
   171→
   172→  /** Start webcam stream. */
   173→  async _startCamera() {
   174→    const stream = await navigator.mediaDevices.getUserMedia({
   175→      video: { width: 320, height: 240, facingMode: 'user' },
   176→    });
   177→    this.video.srcObject = stream;
   178→    await new Promise((resolve) => {
   179→      this.video.onloadedmetadata = () => {
   180→        this.video.play();
   181→        resolve();
   182→      };
   183→    });
   184→  }
   185→
   186→  /** Set up the skeleton overlay canvas. */
   187→  setOverlayCanvas(canvas) {
   188→    this.overlayCanvas = canvas;
   189→    this.overlayCtx = canvas.getContext('2d');
   190→  }
   191→
   192→  /** Continuous processing loop. */
   193→  _processLoop() {
   194→    if (!this.running) return;
   195→
   196→    if (this.video.readyState >= 2) {
   197→      const timestamp = performance.now();
   198→      const results = this.handLandmarker.detectForVideo(this.video, timestamp);
   199→      this._processResults(results);
   200→    }
   201→
   202→    this._animFrameId = requestAnimationFrame(() => this._processLoop());
   203→  }
   204→
   205→  /**
   206→   * Process hand detection results.
   207→   * Uses ONNX inference when available, falls back to heuristic.
   208→   * @param {object} results - MediaPipe HandLandmarker results
   209→   */
   210→  _processResults(results) {
   211→    if (!results.landmarks || results.landmarks.length === 0) {
   212→      this._updateGesture('none', 0, null);
   213→      this._landmarks = null;
   214→      this._drawOverlay(null);
   215→      return;
   216→    }
   217→
   218→    const landmarks = results.landmarks[0]; // Primary hand
   219→    this._landmarks = results.landmarks;
   220→
   221→    // Calculate hand position (palm center = landmark 9, middle finger MCP)
   222→    const palm = landmarks[9];
   223→    // Mirror x since webcam is mirrored
   224→    this._handPosition = { x: 1 - palm.x, y: palm.y };
   225→
   226→    // Two-hand bypass: frame gesture
   227→    if (results.landmarks.length >= 2) {
   228→      this._updateGesture('frame', 0.9, this._handPosition);
   229→      this._drawOverlay(results.landmarks);
   230→      return;
   231→    }
   232→
   233→    // Single hand: run ONNX inference (async, non-blocking)
   234→    if (this.session && !this._isInferring) {
   235→      this._isInferring = true;
   236→      this._runInference(landmarks).finally(() => {
   237→        this._isInferring = false;
   238→      });
   239→    } else if (!this.session) {
   240→      // Fallback to heuristic when ONNX is unavailable
   241→      const heuristic = this._classifyGesture(landmarks);
   242→      this._lastPrediction = heuristic;
   243→    }
   244→
   245→    // Use latest prediction (may be from previous frame if currently inferring)
   246→    this._updateGesture(
   247→      this._lastPrediction.gesture,
   248→      this._lastPrediction.confidence,
   249→      this._handPosition
   250→    );
   251→
   252→    // Draw skeleton overlay
   253→    this._drawOverlay(results.landmarks);
   254→  }
   255→
   256→  /**
   257→   * Run async ONNX inference on landmarks.
   258→   * @param {Array} landmarks - 21 MediaPipe hand landmarks
   259→   */
   260→  async _runInference(landmarks) {
   261→    try {
   262→      const inputData = this._preprocessLandmarks(landmarks);
   263→      if (!inputData) return;
   264→
   265→      const tensor = new ort.Tensor('float32', inputData, [1, 60]);
   266→      const results = await this.session.run({ input: tensor });
   267→      const probabilities = results.output.data;
   268→
   269→      // Find class with highest probability
   270→      let maxProb = -1;
   271→      let bestIdx = -1;
   272→      for (let i = 0; i < probabilities.length; i++) {
   273→        if (probabilities[i] > maxProb) {
   274→          maxProb = probabilities[i];
   275→          bestIdx = i;
   276→        }
   277→      }
   278→
   279→      this._lastPrediction = {
   280→        gesture: GestureController.GESTURE_LABELS[bestIdx],
   281→        confidence: maxProb,
   282→      };
   283→    } catch (error) {
   284→      console.error('Inference error:', error);
   285→    }
   286→  }
   287→
   288→  /**
   289→   * Preprocess 21 MediaPipe landmarks to match the Python training pipeline.
   290→   *
   291→   * Steps:
   292→   *   1. Translate all landmarks relative to the wrist (landmark 0).
   293→   *   2. Scale by the Euclidean distance from wrist to middle finger MCP (landmark 9).
   294→   *   3. Drop the wrist landmark (now all zeros).
   295→   *   4. Flatten to a 60-element Float32Array (20 landmarks x 3 coords).
   296→   *
   297→   * @param {Array} landmarks - Array of 21 {x, y, z} landmark objects
   298→   * @returns {Float32Array|null} - 60-dim preprocessed vector, or null if invalid
   299→   */
   300→  _preprocessLandmarks(landmarks) {
   301→    if (!landmarks || landmarks.length !== 21) return null;
   302→
   303→    const wrist = landmarks[0];
   304→    const middleMCP = landmarks[9];
   305→
   306→    // Distance from wrist to middle MCP (scaling factor)
   307→    const dx = middleMCP.x - wrist.x;
   308→    const dy = middleMCP.y - wrist.y;
   309→    const dz = middleMCP.z - wrist.z;
   310→    const scale = Math.sqrt(dx * dx + dy * dy + dz * dz) || 1.0;
   311→
   312→    const out = new Float32Array(60);
   313→    let idx = 0;
   314→
   315→    // Start from landmark 1 (drop wrist)
   316→    for (let i = 1; i < landmarks.length; i++) {
   317→      const lm = landmarks[i];
   318→      out[idx++] = (lm.x - wrist.x) / scale;
   319→      out[idx++] = (lm.y - wrist.y) / scale;
   320→      out[idx++] = (lm.z - wrist.z) / scale;
   321→    }
   322→
   323→    return out;
   324→  }
   325→
   326→  /**
   327→   * Heuristic gesture classifier (fallback when ONNX is unavailable).
   328→   * Uses distances between finger tips and palm base.
   329→   *
   330→   * Landmark indices (per hand):
   331→   *   0: wrist
   332→   *   1-4: thumb (CMC, MCP, IP, TIP)
   333→   *   5-8: index (MCP, PIP, DIP, TIP)
   334→   *   9-12: middle (MCP, PIP, DIP, TIP)
   335→   *   13-16: ring (MCP, PIP, DIP, TIP)
   336→   *   17-20: pinky (MCP, PIP, DIP, TIP)
   337→   */
   338→  _classifyGesture(lm) {
   339→    const thumbTip = lm[4];
   340→    const indexTip = lm[8];
   341→    const middleTip = lm[12];
   342→    const ringTip = lm[16];
   343→    const pinkyTip = lm[20];
   344→
   345→    const indexMCP = lm[5];
   346→    const middleMCP = lm[9];
   347→    const ringMCP = lm[13];
   348→    const pinkyMCP = lm[17];
   349→
   350→    const wrist = lm[0];
   351→
   352→    // Finger extension: tip is farther from wrist than MCP
   353→    const fingerExtended = (tip, mcp) => {
   354→      const tipDist = this._dist3D(tip, wrist);
   355→      const mcpDist = this._dist3D(mcp, wrist);
   356→      return tipDist > mcpDist * 1.1;
   357→    };
   358→
   359→    const indexExt = fingerExtended(indexTip, indexMCP);
   360→    const middleExt = fingerExtended(middleTip, middleMCP);
   361→    const ringExt = fingerExtended(ringTip, ringMCP);
   362→    const pinkyExt = fingerExtended(pinkyTip, pinkyMCP);
   363→
   364→    // Thumb extension (compare to index MCP)
   365→    const thumbExt = this._dist3D(thumbTip, wrist) > this._dist3D(lm[2], wrist) * 1.1;
   366→
   367→    // Pinch: thumb tip close to index tip
   368→    const pinchDist = this._dist3D(thumbTip, indexTip);
   369→    if (pinchDist < 0.06) {
   370→      return { gesture: 'pinch', confidence: Math.min(1, 1 - pinchDist / 0.06) };
   371→    }
   372→
   373→    // Count extended fingers
   374→    const extCount = [indexExt, middleExt, ringExt, pinkyExt].filter(Boolean).length;
   375→
   376→    // Fist: no fingers extended (and thumb not extended)
   377→    if (extCount === 0 && !thumbExt) {
   378→      return { gesture: 'fist', confidence: 0.85 };
   379→    }
   380→
   381→    // Open hand: all fingers extended
   382→    if (extCount >= 3 && thumbExt) {
   383→      return { gesture: 'open_hand', confidence: 0.8 + extCount * 0.04 };
   384→    }
   385→
   386→    // Default: none with low confidence
   387→    return { gesture: 'none', confidence: 0.3 };
   388→  }
   389→
   390→  /** 3D Euclidean distance between two landmarks. */
   391→  _dist3D(a, b) {
   392→    return Math.sqrt((a.x - b.x) ** 2 + (a.y - b.y) ** 2 + (a.z - b.z) ** 2);
   393→  }
   394→
   395→  /**
   396→   * Update gesture with debounce buffer.
   397→   * Only fires callback when gesture is stable for N frames.
   398→   */
   399→  _updateGesture(gesture, confidence, handPos) {
   400→    // Apply confidence threshold
   401→    const effectiveGesture =
   402→      confidence >= this._confidenceThreshold ? gesture : 'none';
   403→
   404→    this._gestureBuffer.push(effectiveGesture);
   405→    if (this._gestureBuffer.length > this._bufferSize) {
   406→      this._gestureBuffer.shift();
   407→    }
   408→
   409→    // Check if all buffer entries match
   410→    const stable = this._gestureBuffer.every(
   411→      (g) => g === this._gestureBuffer[0]
   412→    );
   413→    const stableGesture = stable ? this._gestureBuffer[0] : this._gesture;
   414→
   415→    if (stableGesture !== this._gesture) {
   416→      this._gesture = stableGesture;
   417→      this._confidence = confidence;
   418→      if (this.onGestureChange) {
   419→        this.onGestureChange(this._gesture, this._confidence, handPos);
   420→      }
   421→    } else {
   422→      this._confidence = confidence;
   423→    }
   424→
   425→    // Always update hand position callback for smooth tracking
   426→    if (handPos && this.onGestureChange && this._gesture !== 'none') {
   427→      this.onGestureChange(this._gesture, this._confidence, handPos);
   428→    }
   429→  }
   430→
   431→  /** Draw hand skeleton on overlay canvas. */
   432→  _drawOverlay(allLandmarks) {
   433→    if (!this.overlayCanvas || !this.overlayCtx) return;
   434→    const ctx = this.overlayCtx;
   435→    const w = this.overlayCanvas.width;
   436→    const h = this.overlayCanvas.height;
   437→
   438→    ctx.clearRect(0, 0, w, h);
   439→
   440→    if (!allLandmarks) return;
   441→
   442→    // Connection pairs for hand skeleton
   443→    const connections = [
   444→      [0, 1], [1, 2], [2, 3], [3, 4],       // thumb
   445→      [0, 5], [5, 6], [6, 7], [7, 8],       // index
   446→      [0, 9], [9, 10], [10, 11], [11, 12],  // middle
   447→      [0, 13], [13, 14], [14, 15], [15, 16],// ring
   448→      [0, 17], [17, 18], [18, 19], [19, 20],// pinky
   449→      [5, 9], [9, 13], [13, 17],            // palm
   450→    ];
   451→
   452→    for (const landmarks of allLandmarks) {
   453→      // Draw connections
   454→      ctx.strokeStyle = 'rgba(100, 180, 255, 0.7)';
   455→      ctx.lineWidth = 2;
   456→      for (const [a, b] of connections) {
   457→        ctx.beginPath();
   458→        // Mirror x for display
   459→        ctx.moveTo((1 - landmarks[a].x) * w, landmarks[a].y * h);
   460→        ctx.lineTo((1 - landmarks[b].x) * w, landmarks[b].y * h);
   461→        ctx.stroke();
   462→      }
   463→
   464→      // Draw landmarks
   465→      for (let i = 0; i < landmarks.length; i++) {
   466→        const lm = landmarks[i];
   467→        ctx.beginPath();
   468→        ctx.arc((1 - lm.x) * w, lm.y * h, 3, 0, Math.PI * 2);
   469→        ctx.fillStyle =
   470→          i === 4 || i === 8 ? 'rgba(255, 100, 100, 0.9)' : 'rgba(255, 255, 255, 0.8)';
   471→        ctx.fill();
   472→      }
   473→    }
   474→  }
   475→
   476→  /** Get current hand position (normalized 0-1, mirrored). */
   477→  getHandPosition() {
   478→    return this._handPosition;
   479→  }
   480→
   481→  /** Get current gesture name. */
   482→  getCurrentGesture() {
   483→    return this._gesture;
   484→  }
   485→
   486→  /** Get current confidence. */
   487→  getConfidence() {
   488→    return this._confidence;
   489→  }
   490→
   491→  /** Stop processing and release resources. */
   492→  destroy() {
   493→    this.running = false;
   494→    if (this._animFrameId) cancelAnimationFrame(this._animFrameId);
   495→    if (this.video.srcObject) {
   496→      this.video.srcObject.getTracks().forEach((t) => t.stop());
   497→      this.video.srcObject = null;
   498→    }
   499→    if (this.handLandmarker) {
   500→      this.handLandmarker.close();
   501→      this.handLandmarker = null;
   502→    }
   503→  }
   504→}
