   369→  function isFist(hand) {
   370→    const wrist = hand[0];
   371→    const tips = [8, 12, 16, 20];
   372→    const pips = [6, 10, 14, 18];
   373→    let closed = 0;
   374→    for (let i = 0; i < tips.length; i++) {
