   426→      canvas.height = video.videoHeight;
   427→    }
   428→
   429→    const width = canvas.width;
   430→    const height = canvas.height;
   431→    ctx.clearRect(0, 0, width, height);
   432→
   433→    // Detect hands
   434→    let results = null;
   435→    if (gestureCtrl && modelLoaded) {
   436→      results = gestureCtrl.detectRaw(video);
   437→    }
   438→
   439→    // ---- SCANNING / LEADERBOARD ----
   440→    if (gameState === 'SCANNING' || gameState === 'LEADERBOARD') {
   441→      // Draw mirrored camera
   442→      ctx.save();
   443→      ctx.translate(width, 0);
   444→      ctx.scale(-1, 1);
   445→      ctx.drawImage(video, 0, 0, width, height);
   446→      ctx.restore();
   447→
   448→      if (gameState === 'SCANNING') {
   449→        handleScanning(results, width, height);
   450→      }
   451→    }
   452→
   453→    // ---- PLAYING / SOLVED ----
   454→    else if ((gameState === 'PLAYING' || gameState === 'SOLVED') && puzzleImageCanvas && boardCoords) {
   455→      // Draw mirrored camera background
   456→      ctx.save();
   457→      ctx.translate(width, 0);
   458→      ctx.scale(-1, 1);
   459→      ctx.drawImage(video, 0, 0, width, height);
   460→      ctx.restore();
   461→
   462→      handlePlaying(results, width, height);
   463→    }
   464→
   465→    // Draw skeleton (except during leaderboard)
   466→    if (results && results.landmarks && results.landmarks.length > 0 && gameState !== 'LEADERBOARD') {
   467→      drawSkeleton(results.landmarks, width, height);
   468→    }
   469→
   470→    requestAnimationFrame(renderLoop);
   471→  }
   472→
   473→  // ---------------------------------------------------------------
   474→  // SCANNING handler
   475→  // ---------------------------------------------------------------
   476→  function handleScanning(results, width, height) {
   477→    if (!results || !results.landmarks || results.landmarks.length < 2) {
   478→      lastFrameCoords = null; // Clear stale frame when fewer than 2 hands
   479→      return;
   480→    }
   481→
   482→    const h1 = results.landmarks[0];
   483→    const h2 = results.landmarks[1];
   484→
   485→    const d1 = Math.hypot(h1[8].x - h1[4].x, h1[8].y - h1[4].y);
   486→    const d2 = Math.hypot(h2[8].x - h2[4].x, h2[8].y - h2[4].y);
   487→
   488→    let validFrame = false;
   489→
   490→    // Frame detection: both hands have spread thumb-index
   491→    if (d1 > FRAME_THRESHOLD && d2 > FRAME_THRESHOLD) {
   492→      const allX = [h1[8].x, h1[4].x, h2[8].x, h2[4].x];
   493→      const allY = [h1[8].y, h1[4].y, h2[8].y, h2[4].y];
   494→      lastFrameCoords = {
   495→        minX: Math.min(...allX),
   496→        maxX: Math.max(...allX),
   497→        minY: Math.min(...allY),
   498→        maxY: Math.max(...allY),
   499→      };
   500→      validFrame = true;
   501→    }
   502→
   503→    // Pinch capture: both hands pinch while frame was established
   504→    if (d1 < PINCH_THRESHOLD && d2 < PINCH_THRESHOLD && lastFrameCoords) {
   505→      const now = Date.now();
   506→      if (now - lastPinchTime > 1000) {
   507→        lastPinchTime = now;
   508→        captureAndStartGame(width, height);
   509→      }
   510→    }
   511→
   512→    // Draw frame overlay
   513→    if (lastFrameCoords && validFrame) {
   514→      const c = lastFrameCoords;
   515→      const sx = (1 - c.maxX) * width;
   516→      const ex = (1 - c.minX) * width;
   517→      const sy = c.minY * height;
   518→      const ey = c.maxY * height;
   519→
   520→      ctx.strokeStyle = '#ccff00';
   521→      ctx.lineWidth = 4;
   522→      ctx.strokeRect(sx, sy, ex - sx, ey - sy);
   523→
   524→      ctx.fillStyle = '#ffffff';
   525→      ctx.font = 'bold 14px monospace';
   526→      ctx.fillText('PINCH TO CAPTURE', sx, sy - 8);
   527→    }
   528→  }
   529→
   530→  // ---------------------------------------------------------------
   531→  // Capture framed area and start game
   532→  // ---------------------------------------------------------------
   533→  function captureAndStartGame(width, height) {
   534→    const c = lastFrameCoords;
   535→    const fullFrame = captureFrame(width, height);
   536→
   537→    // Calculate crop area from frame coordinates
   538→    const sx = (1 - c.maxX) * width;
   539→    const sy = c.minY * height;
   540→    const sw = ((1 - c.minX) * width) - sx;
   541→    const sh = (c.maxY * height) - sy;
   542→
   543→    if (sw <= 0 || sh <= 0) return;
   544→
   545→    // Create cropped image canvas
   546→    const cropCanvas = document.createElement('canvas');
   547→    cropCanvas.width = sw * 2;
   548→    cropCanvas.height = sh * 2;
   549→    const cropCtx = cropCanvas.getContext('2d');
   550→    if (cropCtx) {
   551→      cropCtx.drawImage(fullFrame, sx, sy, sw, sh, 0, 0, cropCanvas.width, cropCanvas.height);
   552→    }
   553→
   554→    puzzleImageCanvas = cropCanvas;
   555→    tiles = SwapPuzzle.generate(COLS, ROWS);
   556→    boardCoords = { ...c };
   557→    startPlaying();
   558→  }
   559→
   560→  // ---------------------------------------------------------------
   561→  // PLAYING handler
   562→  // ---------------------------------------------------------------
   563→  function handlePlaying(results, width, height) {
   564→    const c = boardCoords;
   565→    const boardSX = (1 - c.maxX) * width;
   566→    const boardSY = c.minY * height;
   567→    const boardW = ((1 - c.minX) * width) - boardSX;
   568→    const boardH = (c.maxY * height) - boardSY;
   569→
   570→    let hoverIndex = null;
   571→    let pinching = false;
   572→    let interactingHand = null;
   573→
   574→    // Process hand input
   575→    if (results && results.landmarks && results.landmarks.length > 0) {
   576→      const hand = results.landmarks[0];
   577→      interactingHand = hand;
   578→
   579→      const indexTip = hand[8];
   580→      const thumbTip = hand[4];
   581→
   582→      // Raw pointer position (mirrored)
   583→      const rawX = (1 - (indexTip.x + thumbTip.x) / 2) * width;
   584→      const rawY = ((indexTip.y + thumbTip.y) / 2) * height;
   585→
   586→      // Pinch state
   587→      const dist = Math.hypot(indexTip.x - thumbTip.x, indexTip.y - thumbTip.y);
   588→      pinching = dist < PINCH_THRESHOLD;
   589→
   590→      // Smooth cursor (lerp based on distance)
   591→      const distMove = Math.hypot(rawX - smoothCursor.x, rawY - smoothCursor.y);
   592→      const alpha = distMove > 100 ? 1.0 : 0.4;
   593→      smoothCursor.x = smoothCursor.x * (1 - alpha) + rawX * alpha;
   594→      smoothCursor.y = smoothCursor.y * (1 - alpha) + rawY * alpha;
   595→    }
   596→
   597→    const cursorX = smoothCursor.x;
   598→    const cursorY = smoothCursor.y;
   599→
   600→    // Calculate tile under cursor
   601→    const relX = cursorX - boardSX;
   602→    const relY = cursorY - boardSY;
   603→    if (relX >= 0 && relX <= boardW && relY >= 0 && relY <= boardH) {
   604→      const col = Math.floor(relX / (boardW / COLS));
   605→      const row = Math.floor(relY / (boardH / ROWS));
   606→      if (col >= 0 && col < COLS && row >= 0 && row < ROWS) {
   607→        hoverIndex = row * COLS + col;
   608→      }
   609→    }
   610→
   611→    // Drag & drop logic (only during PLAYING)
   612→    if (gameState === 'PLAYING') {
   613→      if (pinching) {
   614→        if (!isDragging && hoverIndex !== null) {
   615→          // Start drag
   616→          isDragging = true;
   617→          dragTileIndex = hoverIndex;
   618→        }
   619→      } else {
   620→        if (isDragging) {
   621→          // Drop - swap tiles
   622→          if (dragTileIndex !== null && hoverIndex !== null && dragTileIndex !== hoverIndex) {
   623→            [tiles[dragTileIndex], tiles[hoverIndex]] = [tiles[hoverIndex], tiles[dragTileIndex]];
   624→            if (SwapPuzzle.isSolved(tiles)) {
   625→              onSolved();
   626→            }
   627→          }
   628→          isDragging = false;
   629→          dragTileIndex = null;
   630→        }
   631→      }
   632→    }
   633→
   634→    // Render puzzle
   635→    ctx.save();
   636→    ctx.translate(boardSX, boardSY);
   637→
   638→    SwapPuzzle.render(
   639→      ctx,
   640→      puzzleImageCanvas,
   641→      tiles,
   642→      COLS, ROWS,
   643→      boardW, boardH,
   644→      isDragging && dragTileIndex !== null ? { index: dragTileIndex, x: relX, y: relY } : null,
   645→      hoverIndex
   646→    );
   647→
   648→    // Board border
   649→    ctx.strokeStyle = '#ffffff';
   650→    ctx.lineWidth = 4;
   651→    ctx.strokeRect(0, 0, boardW, boardH);
   652→
   653→    ctx.restore();
   654→
   655→    // Draw cursor
   656→    if (results && results.landmarks && results.landmarks.length > 0) {
   657→      ctx.beginPath();
   658→      ctx.arc(cursorX, cursorY, 10, 0, Math.PI * 2);
   659→      if (isDragging) {
   660→        ctx.fillStyle = '#ccff00';
   661→        ctx.fill();
   662→      } else {
   663→        ctx.strokeStyle = '#ccff00';
   664→        ctx.lineWidth = 2;
   665→        ctx.stroke();
   666→      }
   667→    }
   668→
   669→    // Fist detection for reset
   670→    let fistDetected = false;
   671→    if (interactingHand && gameState === 'PLAYING') {
   672→      fistDetected = isFist(interactingHand);
   673→    }
   674→
   675→    if (fistDetected && gameState === 'PLAYING') {
   676→      if (!fistHoldStart) {
   677→        fistHoldStart = performance.now();
   678→      }
   679→      const elapsed = performance.now() - fistHoldStart;
   680→      const progress = Math.min(elapsed / RESET_DWELL_MS, 1);
   681→
   682→      // Draw reset progress
   683→      const cx = width / 2;
   684→      const cy = height / 2;
   685→
   686→      ctx.save();
   687→      ctx.beginPath();
   688→      ctx.arc(cx, cy, 50, 0, Math.PI * 2);
   689→      ctx.fillStyle = 'rgba(0, 0, 0, 0.6)';
   690→      ctx.fill();
   691→
   692→      ctx.beginPath();
   693→      ctx.arc(cx, cy, 50, -Math.PI / 2, -Math.PI / 2 + Math.PI * 2 * progress);
   694→      ctx.strokeStyle = '#ccff00';
   695→      ctx.lineWidth = 6;
   696→      ctx.lineCap = 'round';
   697→      ctx.stroke();
   698→
   699→      ctx.fillStyle = '#ffffff';
   700→      ctx.font = 'bold 14px monospace';
   701→      ctx.textAlign = 'center';
   702→      ctx.textBaseline = 'middle';
   703→      ctx.fillText('RESETTING', cx, cy - 5);
   704→      ctx.font = '10px monospace';
   705→      ctx.fillText('Hold Fist', cx, cy + 10);
   706→      ctx.restore();
   707→
   708→      if (elapsed > RESET_DWELL_MS) {
   709→        resetGame();
   710→      }
   711→    } else {
   712→      fistHoldStart = null;
   713→    }
   714→  }
   715→
