     1→/**
     2→ * GestureController - MediaPipe HandLandmarker integration with
     3→ * ONNX-based MLP gesture classification and optional CNN fusion.
     4→ *
     5→ * When the CNN model is available, late fusion combines MLP (skeleton)
     6→ * and CNN (appearance) predictions via weighted average. Falls back
     7→ * to MLP-only inference when CNN fails to load.
     8→ *
     9→ * Gestures detected (via trained MLP model):
    10→ *   "pinch"     - Thumb tip close to index tip
    11→ *   "fist"      - All fingers curled
    12→ *   "open_hand" - All fingers extended
    13→ *   "frame"     - Two hands forming a rectangle (bypass: both hands detected)
    14→ *   "none"      - No hand or ambiguous pose
    15→ */
    16→class GestureController {
    17→  // Label order matches sklearn LabelEncoder.fit() alphabetical sorting
    18→  static GESTURE_LABELS = ['fist', 'frame', 'none', 'open_hand', 'pinch'];
    19→
    20→  /**
    21→   * @param {HTMLVideoElement} videoElement
    22→   * @param {function} onGestureChange - Called when gesture changes: (gesture, confidence, handPos)
    23→   */
    24→  constructor(videoElement, onGestureChange) {
    25→    this.video = videoElement;
    26→    this.onGestureChange = onGestureChange;
    27→
    28→    this.handLandmarker = null;
    29→    this.camera = null;
    30→    this.running = false;
    31→
    32→    // ONNX inference sessions
    33→    this.session = null;       // MLP session
    34→    this.cnnSession = null;    // CNN session (optional)
    35→    this.fusionEnabled = false; // true when CNN loaded successfully
    36→    this.fusionAlpha = 0.7;    // MLP weight for fusion (MLP dominant: 98% vs ~90%)
    37→    this._isInferring = false;
    38→    this._lastPrediction = { gesture: 'none', confidence: 0 };
    39→
    40→    // Offscreen canvas for hand crop extraction (CNN input)
    41→    this._cropCanvas = document.createElement('canvas');
    42→    this._cropCanvas.width = 224;
    43→    this._cropCanvas.height = 224;
    44→    this._cropCtx = this._cropCanvas.getContext('2d');
    45→
    46→    // Current state
    47→    this._gesture = 'none';
    48→    this._confidence = 0;
    49→    this._handPosition = null; // { x, y } normalized 0-1
    50→    this._landmarks = null;
    51→
    52→    // Debounce: require N consecutive frames of same gesture
    53→    this._gestureBuffer = [];
    54→    this._bufferSize = 3;
    55→
    56→    // Confidence threshold
    57→    this._confidenceThreshold = 0.7;
    58→
    59→    // Canvas for skeleton overlay
    60→    this.overlayCanvas = null;
    61→    this.overlayCtx = null;
    62→
    63→    // Animation frame
    64→    this._animFrameId = null;
    65→  }
    66→
    67→  /**
    68→   * Initialize detector only (MediaPipe + ONNX) without starting camera or loop.
    69→   * Use this when you manage the camera and render loop externally.
    70→   * After calling this, use detectRaw(video) per frame.
    71→   * @returns {Promise<void>}
    72→   */
    73→  async initDetector() {
    74→    const vision = await this._loadMediaPipe();
    75→    const { HandLandmarker, FilesetResolver } = vision;
    76→
    77→    const wasmFileset = await FilesetResolver.forVisionTasks(
    78→      'https://cdn.jsdelivr.net/npm/@mediapipe/tasks-vision@latest/wasm'
    79→    );
    80→
    81→    this.handLandmarker = await HandLandmarker.createFromOptions(wasmFileset, {
    82→      baseOptions: {
    83→        modelAssetPath:
    84→          'https://storage.googleapis.com/mediapipe-models/hand_landmarker/hand_landmarker/float16/latest/hand_landmarker.task',
    85→        delegate: 'GPU',
    86→      },
    87→      runningMode: 'VIDEO',
    88→      numHands: 2,
    89→      minHandDetectionConfidence: 0.5,
    90→      minHandPresenceConfidence: 0.5,
    91→      minTrackingConfidence: 0.5,
    92→    });
    93→
    94→    await this._initONNXSession();
    95→  }
    96→
    97→  /**
    98→   * Detect hands in a video frame. Returns raw MediaPipe results.
    99→   * Call this per-frame from your own render loop.
   100→   * @param {HTMLVideoElement} video
   101→   * @returns {object|null} MediaPipe detection results with .landmarks array
   102→   */
   103→  detectRaw(video) {
   104→    if (!this.handLandmarker || video.readyState < 2) return null;
   105→    return this.handLandmarker.detectForVideo(video, performance.now());
   106→  }
   107→
   108→  /**
   109→   * Classify a single hand's landmarks using ONNX (or heuristic fallback).
   110→   * @param {Array} landmarks - 21 MediaPipe hand landmarks
   111→   * @returns {Promise<{gesture: string, confidence: number}>}
   112→   */
   113→  async classifyLandmarksAsync(landmarks) {
   114→    if (this.session && !this._isInferring) {
   115→      this._isInferring = true;
   116→      try {
   117→        await this._runInference(landmarks);
   118→      } finally {
   119→        this._isInferring = false;
   120→      }
   121→      return { ...this._lastPrediction };
   122→    }
   123→    // Fallback to heuristic
   124→    return this._classifyGesture(landmarks);
   125→  }
   126→
   127→  /**
   128→   * Initialize MediaPipe, ONNX session, and start processing.
   129→   * @returns {Promise<void>}
   130→   */
   131→  async init() {
   132→    // Import MediaPipe vision module from CDN
   133→    const vision = await this._loadMediaPipe();
   134→
   135→    const { HandLandmarker, FilesetResolver } = vision;
   136→
   137→    const wasmFileset = await FilesetResolver.forVisionTasks(
   138→      'https://cdn.jsdelivr.net/npm/@mediapipe/tasks-vision@latest/wasm'
   139→    );
   140→
   141→    this.handLandmarker = await HandLandmarker.createFromOptions(wasmFileset, {
   142→      baseOptions: {
   143→        modelAssetPath:
   144→          'https://storage.googleapis.com/mediapipe-models/hand_landmarker/hand_landmarker/float16/latest/hand_landmarker.task',
   145→        delegate: 'GPU',
   146→      },
   147→      runningMode: 'VIDEO',
   148→      numHands: 2,
   149→      minHandDetectionConfidence: 0.5,
   150→      minHandPresenceConfidence: 0.5,
   151→      minTrackingConfidence: 0.5,
   152→    });
   153→
   154→    // Initialize ONNX inference session
   155→    await this._initONNXSession();
   156→
   157→    // Start camera
   158→    await this._startCamera();
   159→    this.running = true;
   160→    this._processLoop();
   161→  }
   162→
   163→  /** Initialize ONNX Runtime inference sessions (MLP + optional CNN). */
   164→  async _initONNXSession() {
   165→    // MLP session (primary, required)
   166→    try {
   167→      this.session = await ort.InferenceSession.create('./mlp_model.onnx', {
   168→        executionProviders: ['wasm'],
   169→      });
   170→      console.log('MLP ONNX session initialized.');
   171→    } catch (e) {
   172→      console.warn('MLP ONNX session failed to load, falling back to heuristic:', e);
   173→      this.session = null;
   174→    }
   175→
   176→    // CNN session (optional, for fusion)
   177→    try {
   178→      this.cnnSession = await ort.InferenceSession.create('./cnn_model.onnx', {
   179→        executionProviders: ['webgpu', 'wasm'],
   180→      });
   181→      this.fusionEnabled = true;
   182→      console.log('CNN model loaded; fusion mode active.');
   183→    } catch (e) {
   184→      console.warn('CNN model failed to load; MLP-only mode:', e.message);
   185→      this.cnnSession = null;
   186→      this.fusionEnabled = false;
   187→    }
   188→  }
   189→
   190→  /** Dynamically import the MediaPipe vision module. */
   191→  async _loadMediaPipe() {
   192→    // Use dynamic import from CDN
   193→    const module = await import(
   194→      'https://cdn.jsdelivr.net/npm/@mediapipe/tasks-vision@latest'
   195→    );
   196→    return module;
   197→  }
   198→
   199→  /** Start webcam stream. */
   200→  async _startCamera() {
   201→    const stream = await navigator.mediaDevices.getUserMedia({
   202→      video: { width: 320, height: 240, facingMode: 'user' },
   203→    });
   204→    this.video.srcObject = stream;
   205→    await new Promise((resolve) => {
   206→      this.video.onloadedmetadata = () => {
   207→        this.video.play();
   208→        resolve();
   209→      };
   210→    });
   211→  }
   212→
   213→  /** Set up the skeleton overlay canvas. */
   214→  setOverlayCanvas(canvas) {
   215→    this.overlayCanvas = canvas;
   216→    this.overlayCtx = canvas.getContext('2d');
   217→  }
   218→
   219→  /** Continuous processing loop. */
   220→  _processLoop() {
   221→    if (!this.running) return;
   222→
   223→    if (this.video.readyState >= 2) {
   224→      const timestamp = performance.now();
   225→      const results = this.handLandmarker.detectForVideo(this.video, timestamp);
   226→      this._processResults(results);
   227→    }
   228→
   229→    this._animFrameId = requestAnimationFrame(() => this._processLoop());
   230→  }
   231→
   232→  /**
   233→   * Process hand detection results.
   234→   * Uses ONNX inference when available, falls back to heuristic.
   235→   * @param {object} results - MediaPipe HandLandmarker results
   236→   */
   237→  _processResults(results) {
   238→    if (!results.landmarks || results.landmarks.length === 0) {
   239→      this._updateGesture('none', 0, null);
   240→      this._landmarks = null;
   241→      this._drawOverlay(null);
   242→      return;
   243→    }
   244→
   245→    const landmarks = results.landmarks[0]; // Primary hand
   246→    this._landmarks = results.landmarks;
   247→
   248→    // Calculate hand position (palm center = landmark 9, middle finger MCP)
   249→    const palm = landmarks[9];
   250→    // Mirror x since webcam is mirrored
   251→    this._handPosition = { x: 1 - palm.x, y: palm.y };
   252→
   253→    // Two-hand bypass: frame gesture
   254→    if (results.landmarks.length >= 2) {
   255→      this._updateGesture('frame', 0.9, this._handPosition);
   256→      this._drawOverlay(results.landmarks);
   257→      return;
   258→    }
   259→
   260→    // Single hand: run ONNX inference (async, non-blocking)
   261→    if (this.session && !this._isInferring) {
   262→      this._isInferring = true;
   263→      this._runInference(landmarks).finally(() => {
   264→        this._isInferring = false;
   265→      });
   266→    } else if (!this.session) {
   267→      // Fallback to heuristic when ONNX is unavailable
   268→      const heuristic = this._classifyGesture(landmarks);
   269→      this._lastPrediction = heuristic;
   270→    }
   271→
   272→    // Use latest prediction (may be from previous frame if currently inferring)
   273→    this._updateGesture(
   274→      this._lastPrediction.gesture,
   275→      this._lastPrediction.confidence,
   276→      this._handPosition
   277→    );
   278→
   279→    // Draw skeleton overlay
   280→    this._drawOverlay(results.landmarks);
   281→  }
   282→
   283→  /**
   284→   * Run async ONNX inference on landmarks.
   285→   * Uses fused MLP+CNN prediction when fusionEnabled, otherwise MLP-only.
   286→   * @param {Array} landmarks - 21 MediaPipe hand landmarks
   287→   */
   288→  async _runInference(landmarks) {
   289→    try {
   290→      const inputData = this._preprocessLandmarks(landmarks);
   291→      if (!inputData) return;
   292→
   293→      // MLP inference
   294→      const mlpTensor = new ort.Tensor('float32', inputData, [1, 60]);
   295→      const mlpResults = await this.session.run({ input: mlpTensor });
   296→      const mlpOutput = mlpResults.output.data;
   297→
   298→      let probabilities;
   299→
   300→      if (this.fusionEnabled && this.cnnSession) {
   301→        // Fused inference: MLP + CNN
   302→        probabilities = await this._fusedPredict(mlpOutput, landmarks);
   303→      } else {
   304→        // MLP-only: output is already softmaxed probabilities
   305→        probabilities = mlpOutput;
   306→      }
   307→
   308→      // Find class with highest probability
   309→      let maxProb = -1;
   310→      let bestIdx = -1;
   311→      for (let i = 0; i < probabilities.length; i++) {
   312→        if (probabilities[i] > maxProb) {
   313→          maxProb = probabilities[i];
   314→          bestIdx = i;
   315→        }
   316→      }
   317→
   318→      this._lastPrediction = {
   319→        gesture: GestureController.GESTURE_LABELS[bestIdx],
   320→        confidence: maxProb,
   321→      };
   322→    } catch (error) {
   323→      console.error('Inference error:', error);
   324→    }
   325→  }
   326→
   327→  /**
   328→   * Run CNN inference and fuse with MLP output via weighted average.
   329→   * @param {Float32Array} mlpOutput - Raw MLP output (probabilities or logits)
   330→   * @param {Array} landmarks - 21 MediaPipe hand landmarks for crop extraction
   331→   * @returns {Float32Array} Fused probability array
   332→   */
   333→  async _fusedPredict(mlpOutput, landmarks) {
   334→    const mlpProbs = this._softmax(mlpOutput);
   335→
   336→    // Extract hand crop from video frame and run CNN
   337→    const cropTensor = this._extractHandCrop(
   338→      landmarks, this.video.videoWidth, this.video.videoHeight
   339→    );
   340→    const cnnResults = await this.cnnSession.run({ image: cropTensor });
   341→    const cnnProbs = this._softmax(cnnResults.logits.data);
   342→
   343→    // Late fusion: weighted average
   344→    const fused = new Float32Array(mlpProbs.length);
   345→    for (let i = 0; i < mlpProbs.length; i++) {
   346→      fused[i] = this.fusionAlpha * mlpProbs[i] +
   347→                 (1 - this.fusionAlpha) * cnnProbs[i];
   348→    }
   349→    return fused;
   350→  }
   351→
   352→  /**
   353→   * Extract a hand crop from the video frame, resize to 224x224,
   354→   * and convert to a CHW Float32Array with ImageNet normalization.
   355→   *
   356→   * @param {Array} landmarks - 21 MediaPipe hand landmarks (normalized 0-1)
   357→   * @param {number} videoWidth - Video element width in pixels
   358→   * @param {number} videoHeight - Video element height in pixels
   359→   * @returns {ort.Tensor} Float32 tensor of shape [1, 3, 224, 224]
   360→   */
   361→  _extractHandCrop(landmarks, videoWidth, videoHeight) {
   362→    // Compute bounding box from all 21 landmarks
   363→    let minX = Infinity, maxX = -Infinity;
   364→    let minY = Infinity, maxY = -Infinity;
   365→    for (let i = 0; i < landmarks.length; i++) {
   366→      const px = landmarks[i].x * videoWidth;
   367→      const py = landmarks[i].y * videoHeight;
   368→      if (px < minX) minX = px;
   369→      if (px > maxX) maxX = px;
   370→      if (py < minY) minY = py;
   371→      if (py > maxY) maxY = py;
   372→    }
   373→
   374→    // Add 10% padding
   375→    const padFrac = 0.1;
   376→    const bboxW = maxX - minX;
   377→    const bboxH = maxY - minY;
   378→    const x1 = Math.max(0, minX - padFrac * bboxW);
   379→    const y1 = Math.max(0, minY - padFrac * bboxH);
   380→    const x2 = Math.min(videoWidth, maxX + padFrac * bboxW);
   381→    const y2 = Math.min(videoHeight, maxY + padFrac * bboxH);
   382→
   383→    const cropW = x2 - x1;
   384→    const cropH = y2 - y1;
   385→
   386→    // Draw cropped region to offscreen 224x224 canvas
   387→    this._cropCtx.clearRect(0, 0, 224, 224);
   388→    if (cropW > 0 && cropH > 0) {
   389→      this._cropCtx.drawImage(this.video, x1, y1, cropW, cropH, 0, 0, 224, 224);
   390→    }
   391→    const imageData = this._cropCtx.getImageData(0, 0, 224, 224);
   392→    const pixels = imageData.data; // RGBA Uint8ClampedArray
   393→
   394→    // Convert RGBA HWC to CHW Float32 with ImageNet normalization
   395→    // mean = [0.485, 0.456, 0.406], std = [0.229, 0.224, 0.225]
   396→    const mean = [0.485, 0.456, 0.406];
   397→    const std = [0.229, 0.224, 0.225];
   398→    const numPixels = 224 * 224;
   399→    const float32Data = new Float32Array(3 * numPixels);
   400→
   401→    for (let i = 0; i < numPixels; i++) {
   402→      const rgbaIdx = i * 4; // skip alpha (index 3)
   403→      for (let c = 0; c < 3; c++) {
   404→        float32Data[c * numPixels + i] =
   405→          (pixels[rgbaIdx + c] / 255.0 - mean[c]) / std[c];
   406→      }
   407→    }
   408→
   409→    return new ort.Tensor('float32', float32Data, [1, 3, 224, 224]);
   410→  }
   411→
   412→  /**
   413→   * Numerically stable softmax over a Float32Array or typed array.
   414→   * @param {Float32Array|Array} logits - Raw model output
   415→   * @returns {Float32Array} Probability distribution summing to 1
   416→   */
   417→  _softmax(logits) {
   418→    const maxVal = Math.max(...logits);
   419→    const exps = new Float32Array(logits.length);
   420→    let sumExp = 0;
   421→    for (let i = 0; i < logits.length; i++) {
   422→      exps[i] = Math.exp(logits[i] - maxVal);
   423→      sumExp += exps[i];
   424→    }
   425→    for (let i = 0; i < exps.length; i++) {
   426→      exps[i] /= sumExp;
   427→    }
   428→    return exps;
   429→  }
   430→
   431→  /**
   432→   * Preprocess 21 MediaPipe landmarks to match the Python training pipeline.
   433→   *
   434→   * Steps:
   435→   *   1. Translate all landmarks relative to the wrist (landmark 0).
   436→   *   2. Scale by the Euclidean distance from wrist to middle finger MCP (landmark 9).
   437→   *   3. Drop the wrist landmark (now all zeros).
   438→   *   4. Flatten to a 60-element Float32Array (20 landmarks x 3 coords).
   439→   *
   440→   * @param {Array} landmarks - Array of 21 {x, y, z} landmark objects
   441→   * @returns {Float32Array|null} - 60-dim preprocessed vector, or null if invalid
   442→   */
   443→  _preprocessLandmarks(landmarks) {
   444→    if (!landmarks || landmarks.length !== 21) return null;
   445→
   446→    const wrist = landmarks[0];
   447→    const middleMCP = landmarks[9];
   448→
   449→    // Distance from wrist to middle MCP (scaling factor)
   450→    const dx = middleMCP.x - wrist.x;
   451→    const dy = middleMCP.y - wrist.y;
   452→    const dz = middleMCP.z - wrist.z;
   453→    const scale = Math.sqrt(dx * dx + dy * dy + dz * dz) || 1.0;
   454→
   455→    const out = new Float32Array(60);
   456→    let idx = 0;
   457→
   458→    // Start from landmark 1 (drop wrist)
   459→    for (let i = 1; i < landmarks.length; i++) {
   460→      const lm = landmarks[i];
   461→      out[idx++] = (lm.x - wrist.x) / scale;
   462→      out[idx++] = (lm.y - wrist.y) / scale;
   463→      out[idx++] = (lm.z - wrist.z) / scale;
   464→    }
   465→
   466→    return out;
   467→  }
   468→
   469→  /**
   470→   * Heuristic gesture classifier (fallback when ONNX is unavailable).
   471→   * Uses distances between finger tips and palm base.
   472→   *
   473→   * Landmark indices (per hand):
   474→   *   0: wrist
   475→   *   1-4: thumb (CMC, MCP, IP, TIP)
   476→   *   5-8: index (MCP, PIP, DIP, TIP)
   477→   *   9-12: middle (MCP, PIP, DIP, TIP)
   478→   *   13-16: ring (MCP, PIP, DIP, TIP)
   479→   *   17-20: pinky (MCP, PIP, DIP, TIP)
   480→   */
   481→  _classifyGesture(lm) {
   482→    const thumbTip = lm[4];
   483→    const indexTip = lm[8];
   484→    const middleTip = lm[12];
   485→    const ringTip = lm[16];
   486→    const pinkyTip = lm[20];
   487→
   488→    const indexMCP = lm[5];
   489→    const middleMCP = lm[9];
   490→    const ringMCP = lm[13];
   491→    const pinkyMCP = lm[17];
   492→
   493→    const wrist = lm[0];
   494→
   495→    // Finger extension: tip is farther from wrist than MCP
   496→    const fingerExtended = (tip, mcp) => {
   497→      const tipDist = this._dist3D(tip, wrist);
   498→      const mcpDist = this._dist3D(mcp, wrist);
   499→      return tipDist > mcpDist * 1.1;
   500→    };
   501→
   502→    const indexExt = fingerExtended(indexTip, indexMCP);
   503→    const middleExt = fingerExtended(middleTip, middleMCP);
   504→    const ringExt = fingerExtended(ringTip, ringMCP);
   505→    const pinkyExt = fingerExtended(pinkyTip, pinkyMCP);
   506→
   507→    // Thumb extension (compare to index MCP)
   508→    const thumbExt = this._dist3D(thumbTip, wrist) > this._dist3D(lm[2], wrist) * 1.1;
   509→
   510→    // Pinch: thumb tip close to index tip
   511→    const pinchDist = this._dist3D(thumbTip, indexTip);
   512→    if (pinchDist < 0.06) {
   513→      return { gesture: 'pinch', confidence: Math.min(1, 1 - pinchDist / 0.06) };
   514→    }
   515→
   516→    // Count extended fingers
   517→    const extCount = [indexExt, middleExt, ringExt, pinkyExt].filter(Boolean).length;
   518→
   519→    // Fist: no fingers extended (and thumb not extended)
   520→    if (extCount === 0 && !thumbExt) {
   521→      return { gesture: 'fist', confidence: 0.85 };
   522→    }
   523→
   524→    // Open hand: all fingers extended
   525→    if (extCount >= 3 && thumbExt) {
   526→      return { gesture: 'open_hand', confidence: 0.8 + extCount * 0.04 };
   527→    }
   528→
   529→    // Default: none with low confidence
   530→    return { gesture: 'none', confidence: 0.3 };
   531→  }
   532→
   533→  /** 3D Euclidean distance between two landmarks. */
   534→  _dist3D(a, b) {
   535→    return Math.sqrt((a.x - b.x) ** 2 + (a.y - b.y) ** 2 + (a.z - b.z) ** 2);
   536→  }
   537→
   538→  /**
   539→   * Update gesture with debounce buffer.
   540→   * Only fires callback when gesture is stable for N frames.
   541→   */
   542→  _updateGesture(gesture, confidence, handPos) {
   543→    // Apply confidence threshold
   544→    const effectiveGesture =
   545→      confidence >= this._confidenceThreshold ? gesture : 'none';
   546→
   547→    this._gestureBuffer.push(effectiveGesture);
   548→    if (this._gestureBuffer.length > this._bufferSize) {
   549→      this._gestureBuffer.shift();
   550→    }
   551→
   552→    // Check if all buffer entries match
   553→    const stable = this._gestureBuffer.every(
   554→      (g) => g === this._gestureBuffer[0]
   555→    );
   556→    const stableGesture = stable ? this._gestureBuffer[0] : this._gesture;
   557→
   558→    if (stableGesture !== this._gesture) {
   559→      this._gesture = stableGesture;
   560→      this._confidence = confidence;
   561→      if (this.onGestureChange) {
   562→        this.onGestureChange(this._gesture, this._confidence, handPos);
   563→      }
   564→    } else {
   565→      this._confidence = confidence;
   566→    }
   567→
   568→    // Always update hand position callback for smooth tracking
   569→    if (handPos && this.onGestureChange && this._gesture !== 'none') {
   570→      this.onGestureChange(this._gesture, this._confidence, handPos);
   571→    }
   572→  }
   573→
   574→  /** Draw hand skeleton on overlay canvas. */
   575→  _drawOverlay(allLandmarks) {
   576→    if (!this.overlayCanvas || !this.overlayCtx) return;
   577→    const ctx = this.overlayCtx;
   578→    const w = this.overlayCanvas.width;
   579→    const h = this.overlayCanvas.height;
   580→
   581→    ctx.clearRect(0, 0, w, h);
   582→
   583→    if (!allLandmarks) return;
   584→
   585→    // Connection pairs for hand skeleton
   586→    const connections = [
   587→      [0, 1], [1, 2], [2, 3], [3, 4],       // thumb
