   336→    // Extract hand crop from video frame and run CNN
   337→    const cropTensor = this._extractHandCrop(
   338→      landmarks, this.video.videoWidth, this.video.videoHeight
   339→    );
   340→    const cnnResults = await this.cnnSession.run({ image: cropTensor });
