   584→
   585→    // Connection pairs for hand skeleton
   586→    const connections = [
   587→      [0, 1], [1, 2], [2, 3], [3, 4],       // thumb
   588→      [0, 5], [5, 6], [6, 7], [7, 8],       // index
   589→      [0, 9], [9, 10], [10, 11], [11, 12],  // middle
   590→      [0, 13], [13, 14], [14, 15], [15, 16],// ring
